#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        long long X,Y,A,B,K;
        scanf("%lld %lld %lld %lld %lld",&X,&Y,&A,&B,&K);
        long long petrol = X + K*A;
        long long diesel = Y + K*B;
        if(petrol < diesel) printf("PETROL\n");
        else if(petrol > diesel) printf("DIESEL\n");
        else printf("SAME PRICE\n");
    }
    return 0;
}

