#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        X = int(next(it)); Y = int(next(it)); A = int(next(it)); B = int(next(it)); K = int(next(it))
        petrol = X + K * A
        diesel = Y + K * B
        if petrol < diesel:
            out.append("PETROL")
        elif petrol > diesel:
            out.append("DIESEL")
        else:
            out.append("SAME PRICE")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    solve()

